 10→
 11→// --- Unit tests (no DB) ---
 12→
 13→func TestMergeJSONB(t *testing.T) {
 14→	tests := []struct {
 15→		name    string
 16→		dst     []byte
 17→		src     []byte
 18→		want    map[string]any
 19→		wantErr bool
 20→	}{
 21→		{
 22→			name: "both nil",
 23→			dst:  nil,
 24→			src:  nil,
 25→			want: map[string]any{},
 26→		},
 27→		{
 28→			name: "dst nil src has data",
 29→			dst:  nil,
 30→			src:  []byte(`{"a":1}`),
 31→			want: map[string]any{"a": float64(1)},
 32→		},
 33→		{
 34→			name: "src nil dst has data",
 35→			dst:  []byte(`{"a":1}`),
 36→			src:  nil,
 37→			want: map[string]any{"a": float64(1)},
 38→		},
 39→		{
 40→			name: "no overlap",
 41→			dst:  []byte(`{"a":1}`),
 42→			src:  []byte(`{"b":2}`),
 43→			want: map[string]any{"a": float64(1), "b": float64(2)},
 44→		},
 45→		{
 46→			name: "src overwrites dst on conflict",
 47→			dst:  []byte(`{"a":1,"b":2}`),
 48→			src:  []byte(`{"b":99,"c":3}`),
 49→			want: map[string]any{"a": float64(1), "b": float64(99), "c": float64(3)},
 50→		},
 51→		{
 52→			name: "empty objects",
 53→			dst:  []byte(`{}`),
 54→			src:  []byte(`{}`),
 55→			want: map[string]any{},
 56→		},
 57→		{
 58→			name:    "invalid dst",
 59→			dst:     []byte(`not-json`),
 60→			src:     []byte(`{"a":1}`),
 61→			wantErr: true,
 62→		},
 63→		{
 64→			name:    "invalid src",
 65→			dst:     []byte(`{"a":1}`),
 66→			src:     []byte(`not-json`),
 67→			wantErr: true,
 68→		},
 69→	}
 70→
 71→	for _, tc := range tests {
 72→		t.Run(tc.name, func(t *testing.T) {
 73→			got, err := MergeJSONB(tc.dst, tc.src)
 74→			if tc.wantErr {
 75→				if err == nil {
 76→					t.Fatal("expected error, got nil")
 77→				}
 78→				return
 79→			}
 80→			if err != nil {
 81→				t.Fatalf("unexpected error: %v", err)
 82→			}
 83→
 84→			var gotMap map[string]any
 85→			if err := json.Unmarshal(got, &gotMap); err != nil {
 86→				t.Fatalf("output is not valid JSON: %v", err)
 87→			}
 88→
 89→			if len(gotMap) != len(tc.want) {
 90→				t.Fatalf("got %d keys, want %d: %v", len(gotMap), len(tc.want), gotMap)
 91→			}
 92→			for k, wantVal := range tc.want {
 93→				gotVal, ok := gotMap[k]
 94→				if !ok {
 95→					t.Errorf("missing key %q", k)
 96→					continue
 97→				}
 98→				if fmt.Sprintf("%v", gotVal) != fmt.Sprintf("%v", wantVal) {
 99→					t.Errorf("key %q: got %v, want %v", k, gotVal, wantVal)
100→				}
101→			}
102→		})
103→	}
104→}
105→
106→func TestDatasetID(t *testing.T) {
107→	got := datasetID("123456", "ACADEMICS", "enrollment")
108→	want := "123456:ACADEMICS:enrollment"
109→	if got != want {
110→		t.Errorf("got %q, want %q", got, want)
111→	}
