  1→package search
  2→
  3→import "sort"
  4→
  5→// Registry holds every registered search field, keyed by name.
  6→type Registry struct {
  7→	fields map[string]Field
  8→}
  9→
 10→// Lookup returns the Field for the given name, or false if unknown.
 11→func (r *Registry) Lookup(name string) (Field, bool) {
 12→	f, ok := r.fields[name]
 13→	return f, ok
 14→}
 15→
 16→// All returns every registered field in an unspecified order.
 17→func (r *Registry) All() []Field {
 18→	out := make([]Field, 0, len(r.fields))
 19→	for _, f := range r.fields {
 20→		out = append(out, f)
 21→	}
 22→	return out
 23→}
 24→
 25→// Descriptors returns metadata for every registered field. This is the
 26→// contract consumed by the future GET /api/search/fields handler.
 27→func (r *Registry) Descriptors() []FieldDescriptor {
 28→	out := make([]FieldDescriptor, 0, len(r.fields))
 29→	for _, f := range r.fields {
 30→		out = append(out, f.Descriptor())
 31→	}
 32→	return out
 33→}
 34→
 35→// OutputDescriptors returns metadata for fields that appear in search result
 36→// columns (OutputDefault != nil). The caller decides how to order them.
 37→func (r *Registry) OutputDescriptors() []FieldDescriptor {
 38→	out := make([]FieldDescriptor, 0, len(r.fields))
 39→	for _, f := range r.fields {
 40→		d := f.Descriptor()
 41→		if d.OutputDefault != nil {
 42→			out = append(out, d)
 43→		}
 44→	}
 45→	return out
 46→}
 47→
 48→// ExportableDescriptors returns metadata for fields that are exportable and
 49→// have an output representation. Results are ordered by theme (AllThemes order)
 50→// then by registration order within each theme.
 51→func (r *Registry) ExportableDescriptors() []FieldDescriptor {
 52→	// Build theme-index map for sorting.
 53→	themeIndex := make(map[Theme]int, len(AllThemes))
 54→	for i, t := range AllThemes {
 55→		themeIndex[t] = i
 56→	}
 57→
 58→	// Collect qualifying fields preserving registration order.
 59→	type indexedDesc struct {
 60→		regOrder int
 61→		desc     FieldDescriptor
 62→	}
 63→	var items []indexedDesc
 64→	for i, f := range allFields() {
 65→		d := f.Descriptor()
 66→		if d.Exportable != nil && *d.Exportable && d.OutputDefault != nil {
 67→			items = append(items, indexedDesc{regOrder: i, desc: d})
 68→		}
 69→	}
 70→
 71→	// Sort by theme order, stable within theme (registration order).
 72→	sort.SliceStable(items, func(i, j int) bool {
 73→		ti := themeIndex[items[i].desc.Theme]
 74→		tj := themeIndex[items[j].desc.Theme]
 75→		if ti != tj {
 76→			return ti < tj
 77→		}
 78→		return items[i].regOrder < items[j].regOrder
 79→	})
 80→
 81→	out := make([]FieldDescriptor, len(items))
 82→	for i, item := range items {
 83→		out[i] = item.desc
 84→	}
 85→	return out
 86→}
 87→
 88→// NewRegistry constructs and returns a fully populated Registry.
 89→func NewRegistry() *Registry {
 90→	r := &Registry{fields: make(map[string]Field)}
 91→	for _, f := range allFields() {
 92→		r.fields[f.Name()] = f
 93→	}
 94→	return r
 95→}
 96→
 97→// NewRegistryFromFields builds a Registry from an explicit list of fields.
 98→// Intended for testing scenarios that need custom field configurations.
 99→func NewRegistryFromFields(fields []Field) *Registry {
100→	r := &Registry{fields: make(map[string]Field, len(fields))}

  1→package main
  2→
  3→import (
  4→	"context"
  5→	"flag"
  6→	"fmt"
  7→	"log/slog"
  8→	"time"
  9→
 10→	"github.com/jackc/pgx/v5/pgxpool"
 11→	"github.com/ketang/kapow/tools/kapow/internal/config"
 12→	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 13→)
 14→
 15→// Importer defines the interface that all data importers must implement.
 16→type Importer interface {
 17→	// Name returns the subcommand name (e.g. "nces", "rankings").
 18→	Name() string
 19→	// Description returns a short human-readable description.
 20→	Description() string
 21→	// Dependencies returns names of importers that must run before this one.
 22→	Dependencies() []string
 23→	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24→	RegisterFlags(fs *flag.FlagSet)
 25→	// Run executes the import. It may use the pool for DB operations and the
 26→	// fetcher for downloading source data.
 27→	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28→}
 29→
 30→// registry holds all registered importers keyed by name.
 31→var registry = map[string]Importer{}
 32→
 33→// Register adds an importer to the registry. Panics on duplicate name.
 34→func Register(imp Importer) {
 35→	name := imp.Name()
 36→	if _, exists := registry[name]; exists {
 37→		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38→	}
 39→	registry[name] = imp
 40→}
 41→
 42→// Get returns a registered importer by name, or nil if not found.
 43→func Get(name string) Importer {
 44→	return registry[name]
 45→}
 46→
 47→// All returns all registered importers.
 48→func All() map[string]Importer {
 49→	return registry
 50→}
 51→
 52→// RunAll executes all importers in dependency order.
 53→func RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54→	ordered, err := topoSort(registry)
 55→	if err != nil {
 56→		return err
 57→	}
 58→
 59→	for _, imp := range ordered {
 60→		name := imp.Name()
 61→		if len(only) > 0 && !only[name] {
 62→			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63→			continue
 64→		}
 65→		if skip[name] {
 66→			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67→			continue
 68→		}
 69→
 70→		slog.Info("run-all: starting", "importer", name)
 71→		start := time.Now()
 72→		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73→			return fmt.Errorf("run-all: %s: %w", name, err)
 74→		}
 75→		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76→	}
 77→
 78→	return nil
 79→}
 80→
 81→// topoSort returns importers in dependency order using Kahn's algorithm.
 82→func topoSort(importers map[string]Importer) ([]Importer, error) {
 83→	// Build in-degree map and adjacency list.
 84→	inDegree := make(map[string]int)
 85→	dependents := make(map[string][]string) // dep -> list of importers that depend on it
 86→
 87→	for name, imp := range importers {
 88→		if _, ok := inDegree[name]; !ok {
 89→			inDegree[name] = 0
 90→		}
 91→		for _, dep := range imp.Dependencies() {
 92→			inDegree[name]++
 93→			dependents[dep] = append(dependents[dep], name)
 94→		}
 95→	}
 96→
 97→	// Start with importers that have no dependencies.
 98→	var queue []string
 99→	for name, deg := range inDegree {
100→		if deg == 0 {
101→			queue = append(queue, name)
102→		}
103→	}
104→
105→	var result []Importer
106→	for len(queue) > 0 {
107→		name := queue[0]
108→		queue = queue[1:]
109→		if imp, ok := importers[name]; ok {
110→			result = append(result, imp)
111→		}
112→		for _, dep := range dependents[name] {
113→			inDegree[dep]--
114→			if inDegree[dep] == 0 {
115→				queue = append(queue, dep)
116→			}
117→		}
118→	}
119→
120→	if len(result) != len(importers) {
121→		return nil, fmt.Errorf("importer: circular dependency detected")
122→	}
123→
124→	return result, nil
125→}
